var alarmStatus = msg.alarm_1;
var alarmDescriptions = [
    "High String Input Voltage",
    "DC Arc Fault",
    "String Reverse Connection",
    "String Current Backfeed",
    "Abnormal String Power",
    "AFCI Self-Check Fail",
    "Phase Wire Short-Circuited to PE",
    "Grid Loss",
    "Grid Undervoltage",
    "Grid Overvoltage",
    "Grid Voltage Imbalance",
    "Grid Overfrequency",
    "Grid Underfrequency",
    "Unstable Grid Frequency",
    "Output Overcurrent",
    "Output DC Component Overhigh"
];

var severityLevels = [
    "MAJOR", "MAJOR", "MAJOR", "WARNING",
    "WARNING", "MAJOR", "MAJOR", "MAJOR",
    "MAJOR", "MAJOR", "MAJOR", "MAJOR",
    "MAJOR", "MAJOR", "MAJOR", "MAJOR"
];


var alarmArray = [];
var activeAlarmCount = 0;

for (var i = 0; i < 16; i++) {
    var attributeName = 'al_st1_' + alarmDescriptions[i]
        .replace(/\s+/g, '_')
        .replace(/[^a-zA-Z0-9_]/g, ''); // Remove any characters that aren't alphanumeric or underscore
    var value = ((alarmStatus & (1 << i)) !== 0) ? 1 : 0;

    if (value === 1) {
        activeAlarmCount++;
    }

    var alarmObject = {};
    alarmObject[attributeName] = {
        value: value,
        severity: severityLevels[i]
    };
    alarmArray.push(alarmObject);
}

return {
    msg: alarmArray,
    metadata: {
        deviceType: metadata.deviceType ,
        deviceName: metadata.deviceName ,
        ts: metadata.ts
    },
    msgType: msgType || "POST_TELEMETRY_REQUEST"
};

// Function to convert alarm key to a more readable format
