    return key.replace('al_st1_', '').replace(/_/g, ' ');
}

var alarmKey = Object.keys(msg)[0]; // Get the first (and only) key
var alarmDetails = msg[alarmKey]; // Access the value for the key
var alarmValue = alarmDetails.value; // Extract the 'value'
var severity = alarmDetails.severity; // Extract the 'severity'

// Initialize existing metadata if not defined
var updatedMetadata = metadata || {};

// Format the alarm message based on its status
var alarmMessage = formatAlarmName(alarmKey) + (alarmValue === 1 ? " is active" : " is cleared");

// Merge existing metadata with new alarm details
Object.assign(updatedMetadata, {
    deviceType: "default", // Default device type
    alarmType: alarmKey,
    alarmStatus: alarmValue.toString(), // Convert to string for consistency
    severityState: severity,
    alarmMessage: alarmMessage,
    deviceName: "Test Device", // Example device name
    ts: metadata.ts || Date.now() // Add timestamp
});

// Return the result in the desired format
return {
    msg: msg,
    metadata: updatedMetadata,
    msgType: "ALARM"
};

