var gridFaultKeys = [
  'al_st1_Grid_Loss',
  'al_st1_Grid_Undervoltage',
  'al_st1_Grid_Overvoltage',
  'al_st1_Grid_Voltage_Imbalance',
  'al_st1_Grid_Overfrequency',
  'al_st1_Grid_Underfrequency',
  'al_st1_Unstable_Grid_Frequency'
];

var alarmArray = msg; // msg is the array from telemetry
var hasGridFault = false;

for (var i = 0; i < alarmArray.length; i++) {
  var alarmObj = alarmArray[i];
  var keys = Object.keys(alarmObj);

  for (var j = 0; j < keys.length; j++) {
    var key = keys[j];
    if (gridFaultKeys.indexOf(key) !== -1 && alarmObj[key].value === 1) {
      hasGridFault = true;
      break;
    }
  }
  if (hasGridFault) break;
}

return {
  msg: { grid_availability: hasGridFault ? 0 : 1 },
  metadata: metadata,
  msgType: 'POST_TELEMETRY_REQUEST'
};

function detectToggle(msg, metadata, msgType) {
    var currentValue = parseInt(msg.grid_availability);
    var prevRaw = metadata.ss_grid_availability || metadata.cs_grid_availability;
    var previousValue = parseInt(prevRaw || '0');
    if (previousValue === 1 && currentValue === 0) {
        return ['GRID_LOST'];
    } else if (previousValue === 0 && currentValue === 1) {
        return ['GRID_RESTORED'];
    }
    return ['NO_CHANGE'];
}
return detectToggle(msg, metadata, msgType);

