var now = new Date().getTime();

// Sri Lanka Time = UTC + 5:30
var SL_OFFSET_MS = 5.5 * 60 * 60 * 1000;

function toSLTime(timestamp) {
    var d = new Date(timestamp + SL_OFFSET_MS);
    var year = d.getUTCFullYear();
    var month = ('0' + (d.getUTCMonth() + 1)).slice(-2);
    var day = ('0' + d.getUTCDate()).slice(-2);
    var hours = ('0' + d.getUTCHours()).slice(-2);
    var minutes = ('0' + d.getUTCMinutes()).slice(-2);
    var seconds = ('0' + d.getUTCSeconds()).slice(-2);
    return year + '-' + month + '-' + day + ' ' + hours + ':' + minutes + ':' + seconds;
}

// Read grid_lost_time from metadata (loaded by Originator Attributes node)
// Try both prefixes: ss_ and cs_
var gridLostTimeRaw = metadata.ss_grid_lost_time || metadata.cs_grid_lost_time || '0';
var gridLostTime = parseInt(gridLostTimeRaw);

// Read existing total lost ms
var totalLostMsRaw = metadata.ss_grid_total_lost_ms || metadata.cs_grid_total_lost_ms || '0';
var totalLostMs = parseInt(totalLostMsRaw);

// Calculate downtime for this outage
var downtimeMs = 0;
if (gridLostTime > 0 && now > gridLostTime) {
    downtimeMs = now - gridLostTime;
}

// Add to total
totalLostMs = totalLostMs + downtimeMs;

// Calculate downtime in readable format
var downtimeSeconds = Math.floor(downtimeMs / 1000);
var downtimeMinutes = Math.floor(downtimeSeconds / 60);
var downtimeHours = Math.floor(downtimeMinutes / 60);
var remainingMinutes = downtimeMinutes % 60;
var remainingSeconds = downtimeSeconds % 60;
var downtimeReadable = downtimeHours + 'h ' + remainingMinutes + 'm ' + remainingSeconds + 's';

// Calculate availability percentage using ACTUAL DAYLIGHT HOURS
// sun_daylight_ms is saved daily by the Sunrise/Sunset API nodes
var sunDaylightRaw = metadata.ss_sun_daylight_ms || metadata.cs_sun_daylight_ms || '0';
var sunDaylightMs = parseInt(sunDaylightRaw);

// Use sun daylight hours if available, otherwise fallback to 24h
var windowMs = (sunDaylightMs > 0) ? sunDaylightMs : (24 * 60 * 60 * 1000);

var availabilityPercent = 100.0;
if (totalLostMs > 0) {
    availabilityPercent = parseFloat((((windowMs - totalLostMs) / windowMs) * 100).toFixed(2));
}
if (availabilityPercent < 0) { availabilityPercent = 0; }
if (availabilityPercent > 100) { availabilityPercent = 100; }

// Total lost in readable format
var totalSeconds = Math.floor(totalLostMs / 1000);
var totalMinutes = Math.floor(totalSeconds / 60);
var totalHours = Math.floor(totalMinutes / 60);
var totalDays = Math.floor(totalHours / 24);
var tRemHours = totalHours % 24;
var tRemMinutes = totalMinutes % 60;
var tRemSeconds = totalSeconds % 60;
var totalLostReadable = '';
if (totalDays > 0) { totalLostReadable += totalDays + 'd '; }
if (tRemHours > 0 || totalDays > 0) { totalLostReadable += tRemHours + 'h '; }
totalLostReadable += tRemMinutes + 'm ' + tRemSeconds + 's';

var newMsg = {
    grid_on_time: now,
    grid_on_time_readable: toSLTime(now),
    grid_last_downtime_ms: downtimeMs,
    grid_last_downtime_minutes: parseFloat((downtimeMs / 60000).toFixed(2)),
    grid_last_downtime_readable: downtimeReadable,
    grid_total_lost_ms: totalLostMs,
    grid_total_lost_readable: totalLostReadable,
    grid_availability_percent: availabilityPercent,
    // Debug info - remove these after confirming it works
    // debug_grid_lost_time_raw: gridLostTimeRaw,
    // debug_grid_lost_time_parsed: gridLostTime,
    // debug_now: now,
    // debug_calculated_diff: downtimeMs
};

return { msg: newMsg, metadata: metadata, msgType: 'POST_ATTRIBUTES_REQUEST' };

var gridFaultKeys = [
  'al_st1_Grid_Loss',
  'al_st1_Grid_Undervoltage',
  'al_st1_Grid_Overvoltage',
  'al_st1_Grid_Voltage_Imbalance',
  'al_st1_Grid_Overfrequency',
  'al_st1_Grid_Underfrequency',
  'al_st1_Unstable_Grid_Frequency'
];

var alarmArray = msg; // msg is the array from telemetry
var hasGridFault = false;

for (var i = 0; i < alarmArray.length; i++) {
  var alarmObj = alarmArray[i];
  var keys = Object.keys(alarmObj);

  for (var j = 0; j < keys.length; j++) {
    var key = keys[j];
    if (gridFaultKeys.indexOf(key) !== -1 && alarmObj[key].value === 1) {
      hasGridFault = true;
      break;
    }
  }
  if (hasGridFault) break;
}

return {
  msg: { grid_availability: hasGridFault ? 0 : 1 },
  metadata: metadata,
  msgType: 'POST_ATTRIBUTES_REQUEST'
};

// The REST API Call node returns the response body as msg
// Some TB versions pass it as a string, some as parsed JSON
var response = msg;
if (typeof response === 'string') {
    response = JSON.parse(response);
}

// Sri Lanka offset for readable times
var SL_OFFSET_MS = 5.5 * 60 * 60 * 1000;

var sunRiseMs = 0;
var sunSetMs = 0;
var dayLengthSec = 0;
var sunRiseReadable = 'N/A';
var sunSetReadable = 'N/A';

if (response && response.status === 'OK' && response
    .results) {
    var r = response.results;

    // day_length is in seconds
    dayLengthSec = parseInt(r.day_length) || 0;

    // Parse ISO timestamps
    if (r.sunrise) {
        sunRiseMs = new Date(r.sunrise).getTime();
        var slRise = new Date(sunRiseMs + SL_OFFSET_MS);
        sunRiseReadable = ('0' + slRise.getUTCHours())
            .slice(-2) + ':' +
            ('0' + slRise.getUTCMinutes()).slice(-2);
    }
    if (r.sunset) {
        sunSetMs = new Date(r.sunset).getTime();
        var slSet = new Date(sunSetMs + SL_OFFSET_MS);
        sunSetReadable = ('0' + slSet.getUTCHours()).slice(-
                2) + ':' +
            ('0' + slSet.getUTCMinutes()).slice(-2);
    }
}

// Daylight in milliseconds
var daylightMs = dayLengthSec * 1000;

// Readable daylight duration
var dlHours = Math.floor(dayLengthSec / 3600);
var dlMins = Math.floor((dayLengthSec % 3600) / 60);
var daylightReadable = dlHours + 'h ' + dlMins + 'm';

var newMsg = {
    sun_rise_ms: sunRiseMs,
    sun_set_ms: sunSetMs,
    sun_rise_readable: sunRiseReadable,
    sun_set_readable: sunSetReadable,
    sun_daylight_sec: dayLengthSec,
    // sun_daylight_ms: daylightMs,
    sun_daylight_readable: daylightReadable,
    sun_last_updated: new Date().getTime()
};

// Clean metadata — strip HTTP response headers added by REST API Call node
// (Content-Type, Server, X-Frame-Options, etc. pollute the metadata)
// Only keep the essential TB fields needed for Save Attributes to work
var cleanMetadata = {
    deviceName: metadata.deviceName || '',
    deviceType: metadata.deviceType || ''
};

return {
    msg: newMsg,
    metadata: cleanMetadata,
